INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('iPhone Will Not Charge: Tristar / Tigris Diagnosis', 'Repair Guides/iPhone/Charging', '<p>No-charge faults on iPhones frequently trace back to the USB control IC (Tristar on 5 through 7, Tigris on 8 and newer) or the charging port flex.</p><p>Always rule out the cheap parts first: swap a known-good cable and charge port flex before touching the board.</p><ul><li>Confirm the device draws current on a USB ammeter. A dead-short or zero draw points to the board.</li><li>Measure PP_VCC_MAIN / battery voltage and the Tristar supply rails in diode mode for shorts.</li><li>Reflow or replace Tristar/Tigris if data lines are dead but the port flex tests good.</li><li>After replacement, verify the device negotiates charging and shows in the computer.</li></ul>', 'No-charge faults on iPhones frequently trace back to the USB control IC (Tristar on 5 through 7, Tigris on 8 and newer) or the charging port flex. Always rule out the cheap parts first: swap a known-good cable and charge port flex before touching the board. Confirm the device draws current on a USB ammeter. A dead-short or zero draw points to the board. Measure PP_VCC_MAIN / battery voltage and the Tristar supply rails in diode mode for shorts. Reflow or replace Tristar/Tigris if data lines are dead but the port flex tests good. After replacement, verify the device negotiates charging and shows in the computer.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('iPhone 7 Audio IC (Loop Disease)', 'Repair Guides/iPhone/Audio', '<p>The iPhone 7 and 7 Plus audio codec IC (U3101) suffers from flexing-induced solder fatigue, known as Loop Disease.</p><p>Symptoms: greyed-out or spinning speaker icon on calls, no microphone, stuck on Voice Memos.</p><ul><li>A common field fix is bridging pad C12 to restore the clock, but the proper repair is reballing or replacing U3101.</li><li>Reflow rarely lasts; reball with low-temp paste and add a jumper if pads are lifted.</li><li>Test microphone and speakerphone after the repair.</li></ul>', 'The iPhone 7 and 7 Plus audio codec IC (U3101) suffers from flexing-induced solder fatigue, known as Loop Disease. Symptoms: greyed-out or spinning speaker icon on calls, no microphone, stuck on Voice Memos. A common field fix is bridging pad C12 to restore the clock, but the proper repair is reballing or replacing U3101. Reflow rarely lasts; reball with low-temp paste and add a jumper if pads are lifted. Test microphone and speakerphone after the repair.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('iPhone 6 Plus Touch Disease', 'Repair Guides/iPhone/Touch', '<p>The iPhone 6 Plus (and 6) can develop intermittent or dead touch from the Meson/Cumulus touch IC pair losing connection as the board flexes.</p><p>Symptoms: a flickering grey bar at the top of the screen, then unresponsive touch.</p><ul><li>Reflow is a temporary fix; reball or replace the touch ICs and reinforce the board.</li><li>Underfill the touch ICs to resist future flexing.</li></ul>', 'The iPhone 6 Plus (and 6) can develop intermittent or dead touch from the Meson/Cumulus touch IC pair losing connection as the board flexes. Symptoms: a flickering grey bar at the top of the screen, then unresponsive touch. Reflow is a temporary fix; reball or replace the touch ICs and reinforce the board. Underfill the touch ICs to resist future flexing.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('iPhone No Backlight: Check the Boost Circuit', 'Repair Guides/iPhone/Backlight', '<p>No-backlight (image visible under bright light, but dark) points at the backlight boost circuit: the backlight IC, the inductor (coil), and the diode.</p><p>On the iPhone 6 these are U1502, L1503, and D1501.</p><ul><li>Inspect for liquid damage or a bent connector pin that shorted the backlight line.</li><li>Measure the backlight LED voltage; a missing boost voltage means IC, coil, or diode.</li><li>Replace failed components and confirm the coil is not open.</li></ul>', 'No-backlight (image visible under bright light, but dark) points at the backlight boost circuit: the backlight IC, the inductor (coil), and the diode. On the iPhone 6 these are U1502, L1503, and D1501. Inspect for liquid damage or a bent connector pin that shorted the backlight line. Measure the backlight LED voltage; a missing boost voltage means IC, coil, or diode. Replace failed components and confirm the coil is not open.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('MacBook No Power: PPBUS_G3H and PP3V42_G3H', 'Repair Guides/MacBook/No Power', '<p>On Intel MacBooks, two rails must be healthy before the board will power: PPBUS_G3H (main bus, 8.6 to 12.6V) and PP3V42_G3H (always-on 3.42V).</p><p>If PPBUS_G3H is missing or shorted, the SMC will never sequence the board on.</p><ul><li>Measure PPBUS_G3H. Low or zero with the charger connected suggests a short on the bus.</li><li>Use diode-mode and a thermal camera to find the shorted component pulling the rail down.</li><li>Confirm PP3V42_G3H and PPVRTC_G3H, then check the SMC and charging IC sequencing.</li></ul>', 'On Intel MacBooks, two rails must be healthy before the board will power: PPBUS_G3H (main bus, 8.6 to 12.6V) and PP3V42_G3H (always-on 3.42V). If PPBUS_G3H is missing or shorted, the SMC will never sequence the board on. Measure PPBUS_G3H. Low or zero with the charger connected suggests a short on the bus. Use diode-mode and a thermal camera to find the shorted component pulling the rail down. Confirm PP3V42_G3H and PPVRTC_G3H, then check the SMC and charging IC sequencing.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('MacBook Liquid Damage Recovery', 'Repair Guides/MacBook/Liquid', '<p>Liquid (especially sugary or salty drinks) corrodes traces and shorts rails. Time matters: corrosion spreads while powered.</p><p>Do not attempt to power a liquid-damaged board until it is cleaned.</p><ul><li>Disconnect the battery immediately.</li><li>Clean the board in an ultrasonic bath or with isopropyl alcohol and a brush.</li><li>Inspect under the microscope for corrosion around the PMIC, SMC, and CPU rails.</li><li>Reflow or replace corroded components and re-test rails before reassembly.</li></ul>', 'Liquid (especially sugary or salty drinks) corrodes traces and shorts rails. Time matters: corrosion spreads while powered. Do not attempt to power a liquid-damaged board until it is cleaned. Disconnect the battery immediately. Clean the board in an ultrasonic bath or with isopropyl alcohol and a brush. Inspect under the microscope for corrosion around the PMIC, SMC, and CPU rails. Reflow or replace corroded components and re-test rails before reassembly.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Nintendo Switch Won''t Charge: M92T36 and P13USB', 'Repair Guides/Console/Switch', '<p>The Switch charging path runs USB-C to the M92T36 PD/charging IC, then to BQ24193 and the battery.</p><p>A failed M92T36 causes no-charge, overheating around the USB-C port, and sometimes backlight issues.</p><ul><li>Inspect the USB-C port for bent or burnt pins; reflow or replace the port first.</li><li>Check for shorts on the 5V VBUS and the M92T36 supply rails.</li><li>Replace M92T36 with a genuine part; counterfeit chips fail quickly.</li><li>If dock video is also dead, check P13USB.</li></ul>', 'The Switch charging path runs USB-C to the M92T36 PD/charging IC, then to BQ24193 and the battery. A failed M92T36 causes no-charge, overheating around the USB-C port, and sometimes backlight issues. Inspect the USB-C port for bent or burnt pins; reflow or replace the port first. Check for shorts on the 5V VBUS and the M92T36 supply rails. Replace M92T36 with a genuine part; counterfeit chips fail quickly. If dock video is also dead, check P13USB.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Nintendo Switch No Dock Video: P13USB', 'Repair Guides/Console/Switch', '<p>When the Switch works handheld but shows no picture in the dock, the P13USB USB/display mux is the usual cause.</p><p>It routes USB 3.0 and DisplayPort signals to the USB-C connector.</p><ul><li>Confirm the dock and HDMI cable work with another console.</li><li>Replace P13USB; it is small and static-sensitive, so use proper hot-air technique.</li><li>Test docking after the repair.</li></ul>', 'When the Switch works handheld but shows no picture in the dock, the P13USB USB/display mux is the usual cause. It routes USB 3.0 and DisplayPort signals to the USB-C connector. Confirm the dock and HDMI cable work with another console. Replace P13USB; it is small and static-sensitive, so use proper hot-air technique. Test docking after the repair.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('PS4 HDMI Port Replacement and No-Video', 'Repair Guides/Console/PS4', '<p>PS4 no-video is most often a physically damaged HDMI port or a failed HDMI encoder (MN864729, or MN86471A on older units).</p><p>Inspect the port pins under magnification before assuming the IC failed.</p><ul><li>Reflow or replace the HDMI port; many no-video PS4s are just bent center pins.</li><li>If the port is good and there is still no signal, replace the HDMI encoder IC.</li><li>Confirm standby and APU power rails are present.</li></ul>', 'PS4 no-video is most often a physically damaged HDMI port or a failed HDMI encoder (MN864729, or MN86471A on older units). Inspect the port pins under magnification before assuming the IC failed. Reflow or replace the HDMI port; many no-video PS4s are just bent center pins. If the port is good and there is still no signal, replace the HDMI encoder IC. Confirm standby and APU power rails are present.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('PS4 No Power / Blue Light', 'Repair Guides/Console/PS4', '<p>A PS4 that clicks or shows a blinking blue light and shuts off may have a PSU, APU power, or overheating fault.</p><p>Rule out the power supply and thermal paste before board-level work.</p><ul><li>Test the internal PSU outputs.</li><li>Reapply thermal paste and check the APU is not lifted.</li><li>Measure standby rails and the BD7956 power management outputs.</li></ul>', 'A PS4 that clicks or shows a blinking blue light and shuts off may have a PSU, APU power, or overheating fault. Rule out the power supply and thermal paste before board-level work. Test the internal PSU outputs. Reapply thermal paste and check the APU is not lifted. Measure standby rails and the BD7956 power management outputs.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('PS5 HDMI Retimer Replacement', 'Repair Guides/Console/PS5', '<p>PS5 no-video commonly comes from a damaged HDMI port or the HDMI retimer IC near it.</p><p>The port and the retimer are close together; port damage often takes out the retimer.</p><ul><li>Inspect and reflow/replace the HDMI port.</li><li>If the port is good, replace the HDMI retimer with hot air and fresh paste.</li><li>Test all resolutions after the repair.</li></ul>', 'PS5 no-video commonly comes from a damaged HDMI port or the HDMI retimer IC near it. The port and the retimer are close together; port damage often takes out the retimer. Inspect and reflow/replace the HDMI port. If the port is good, replace the HDMI retimer with hot air and fresh paste. Test all resolutions after the repair.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Water Damage First Response', 'Repair Guides/General/Liquid', '<p>The first hour matters most with liquid damage. The two worst things a customer can do are charge the device and try to power it on.</p><p>Set expectations early: liquid damage is a best-effort repair, not a guaranteed one.</p><ul><li>Power off and disconnect the battery as soon as possible.</li><li>Do not use rice; it does nothing for corrosion.</li><li>Open the device, remove shields, and clean with isopropyl alcohol.</li><li>Inspect under the microscope and address corrosion before testing.</li></ul>', 'The first hour matters most with liquid damage. The two worst things a customer can do are charge the device and try to power it on. Set expectations early: liquid damage is a best-effort repair, not a guaranteed one. Power off and disconnect the battery as soon as possible. Do not use rice; it does nothing for corrosion. Open the device, remove shields, and clean with isopropyl alcohol. Inspect under the microscope and address corrosion before testing.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Finding Shorts: Diode Mode Basics', 'Repair Guides/Technique/Shorts', '<p>Diode mode on a multimeter measures the voltage drop across a junction and is the fastest way to find shorts to ground on a rail.</p><p>A reading near zero (a few millivolts) on a power rail usually means a dead short.</p><ul><li>Set the meter to diode mode, black probe on ground.</li><li>Probe the rail. Compare to a known-good board or the other side of the same rail.</li><li>Very low readings indicate a shorted capacitor or IC pulling the rail down.</li></ul>', 'Diode mode on a multimeter measures the voltage drop across a junction and is the fastest way to find shorts to ground on a rail. A reading near zero (a few millivolts) on a power rail usually means a dead short. Set the meter to diode mode, black probe on ground. Probe the rail. Compare to a known-good board or the other side of the same rail. Very low readings indicate a shorted capacitor or IC pulling the rail down.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Finding Shorts: Thermal Camera and Freeze Spray', 'Repair Guides/Technique/Shorts', '<p>When diode mode points to a rail but not a specific part, heat reveals the culprit. A shorted component dissipates power and warms up.</p><p>A thermal camera or freeze spray (which evaporates fastest over the hot part) both work.</p><ul><li>Apply a current-limited supply to the shorted rail at low voltage.</li><li>Watch the thermal camera for the component that heats first.</li><li>Alternatively, mist freeze spray and watch where it clears first.</li><li>Remove or replace the shorted component and re-test the rail.</li></ul>', 'When diode mode points to a rail but not a specific part, heat reveals the culprit. A shorted component dissipates power and warms up. A thermal camera or freeze spray (which evaporates fastest over the hot part) both work. Apply a current-limited supply to the shorted rail at low voltage. Watch the thermal camera for the component that heats first. Alternatively, mist freeze spray and watch where it clears first. Remove or replace the shorted component and re-test the rail.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Injecting Voltage Safely', 'Repair Guides/Technique/Shorts', '<p>Voltage injection forces current into a shorted rail to heat the faulty part, but too much voltage or current can damage good components.</p><p>Always current-limit and stay at or below the rail''s normal voltage.</p><ul><li>Set a bench supply to the rail voltage with a low current limit.</li><li>Inject on the rail and ground, never reverse polarity.</li><li>Find the hot component, then power down before removing it.</li></ul>', 'Voltage injection forces current into a shorted rail to heat the faulty part, but too much voltage or current can damage good components. Always current-limit and stay at or below the rail''s normal voltage. Set a bench supply to the rail voltage with a low current limit. Inject on the rail and ground, never reverse polarity. Find the hot component, then power down before removing it.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('BGA Reball Process Overview', 'Repair Guides/Technique/BGA', '<p>Reballing replaces the solder balls under a BGA chip. It is required after removing a chip for reuse, or when joints have cracked.</p><p>Cleanliness and the right ball size are the difference between a lasting repair and a callback.</p><ul><li>Remove the chip with hot air and a controlled profile.</li><li>Wick the old solder flat and clean the pads with flux and alcohol.</li><li>Use a stencil and the correct ball size to apply fresh balls.</li><li>Reflow the balls, clean, then re-seat the chip with fresh flux.</li></ul>', 'Reballing replaces the solder balls under a BGA chip. It is required after removing a chip for reuse, or when joints have cracked. Cleanliness and the right ball size are the difference between a lasting repair and a callback. Remove the chip with hot air and a controlled profile. Wick the old solder flat and clean the pads with flux and alcohol. Use a stencil and the correct ball size to apply fresh balls. Reflow the balls, clean, then re-seat the chip with fresh flux.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Hot Air Profiles for Common Packages', 'Repair Guides/Technique/Hot Air', '<p>Different packages need different airflow and temperature. Too aggressive and you lift pads or warp the board; too gentle and joints do not flow.</p><p>Preheat the board to reduce thermal shock, especially on large ground planes.</p><ul><li>Small WLCSP/QFN: lower airflow, focused nozzle, watch surrounding parts.</li><li>Large BGA: preheat, wider nozzle, steady ramp to reflow.</li><li>Use flux to improve heat transfer and protect joints.</li></ul>', 'Different packages need different airflow and temperature. Too aggressive and you lift pads or warp the board; too gentle and joints do not flow. Preheat the board to reduce thermal shock, especially on large ground planes. Small WLCSP/QFN: lower airflow, focused nozzle, watch surrounding parts. Large BGA: preheat, wider nozzle, steady ramp to reflow. Use flux to improve heat transfer and protect joints.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Soldering Iron Tip Care', 'Repair Guides/Technique/Soldering', '<p>A clean, tinned tip transfers heat efficiently. Oxidized tips ruin joints and tempt you to crank the temperature.</p><p>Keep the iron at the lowest temperature that reliably flows your solder.</p><ul><li>Tin the tip on power-up and before storing.</li><li>Wipe on brass wool, not a dry sponge, between joints.</li><li>Use tip tinner to recover a lightly oxidized tip.</li></ul>', 'A clean, tinned tip transfers heat efficiently. Oxidized tips ruin joints and tempt you to crank the temperature. Keep the iron at the lowest temperature that reliably flows your solder. Tin the tip on power-up and before storing. Wipe on brass wool, not a dry sponge, between joints. Use tip tinner to recover a lightly oxidized tip.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Flux Types: No-Clean, Rosin, Water-Soluble', 'Repair Guides/Materials/Flux', '<p>Flux removes oxidation so solder wets properly. The three common families behave differently and need different cleanup.</p><p>Match the flux to the job and always clean residue on fine-pitch work.</p><ul><li>No-clean: low residue, convenient, but still clean for reliability on dense boards.</li><li>Rosin: strong, classic, requires alcohol cleanup.</li><li>Water-soluble: very active, must be fully washed off or it corrodes.</li></ul>', 'Flux removes oxidation so solder wets properly. The three common families behave differently and need different cleanup. Match the flux to the job and always clean residue on fine-pitch work. No-clean: low residue, convenient, but still clean for reliability on dense boards. Rosin: strong, classic, requires alcohol cleanup. Water-soluble: very active, must be fully washed off or it corrodes.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('ESD Safety at the Bench', 'Repair Guides/Safety/ESD', '<p>Static discharge can damage ICs invisibly, causing intermittent or delayed failures. Microsoldering work is especially sensitive.</p><p>A grounded mat and wrist strap are cheap insurance.</p><ul><li>Use an ESD mat connected to ground.</li><li>Wear a wrist strap when handling boards and loose ICs.</li><li>Store sensitive parts in anti-static bags.</li></ul>', 'Static discharge can damage ICs invisibly, causing intermittent or delayed failures. Microsoldering work is especially sensitive. A grounded mat and wrist strap are cheap insurance. Use an ESD mat connected to ground. Wear a wrist strap when handling boards and loose ICs. Store sensitive parts in anti-static bags.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Li-ion Battery Safety', 'Repair Guides/Safety/Battery', '<p>Lithium batteries store a lot of energy and can vent or ignite if punctured, crushed, or shorted.</p><p>Swollen batteries are a disposal item, not a charge-and-test item.</p><ul><li>Never puncture or bend a battery during removal.</li><li>Isolate swollen batteries and dispose of them properly.</li><li>Keep a fire-safe container or sand bucket nearby.</li></ul>', 'Lithium batteries store a lot of energy and can vent or ignite if punctured, crushed, or shorted. Swollen batteries are a disposal item, not a charge-and-test item. Never puncture or bend a battery during removal. Isolate swollen batteries and dispose of them properly. Keep a fire-safe container or sand bucket nearby.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Laptop No Power: Adapter, Charger IC, EC Reset', 'Repair Guides/Laptop/No Power', '<p>Laptop no-power has a logical order: confirm the adapter, then the DC-in and charging IC, then the embedded controller and power sequencing.</p><p>Many no-power laptops are simply a dead adapter or a stuck EC.</p><ul><li>Verify the adapter outputs the correct voltage.</li><li>Check the DC jack and the charging IC enable rail.</li><li>Try an EC reset (hold power with no battery/adapter), then re-test.</li><li>Move to board-level rail measurement if power still does not sequence.</li></ul>', 'Laptop no-power has a logical order: confirm the adapter, then the DC-in and charging IC, then the embedded controller and power sequencing. Many no-power laptops are simply a dead adapter or a stuck EC. Verify the adapter outputs the correct voltage. Check the DC jack and the charging IC enable rail. Try an EC reset (hold power with no battery/adapter), then re-test. Move to board-level rail measurement if power still does not sequence.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Reading Boardview and Schematic Files', 'Repair Guides/Technique/Boardview', '<p>Boardview files (.brd, .asc, .cad) let you locate components, nets, and test points on a board, and schematics show how rails are generated.</p><p>userrepair opens boardview and schematic files in your system''s default viewer from the Board Tools page.</p><ul><li>Use the boardview to jump from a net name to its test points.</li><li>Cross-reference the schematic to see which IC generates a rail.</li><li>Log the expected values you find into the board''s test-point index.</li></ul>', 'Boardview files (.brd, .asc, .cad) let you locate components, nets, and test points on a board, and schematics show how rails are generated. userrepair opens boardview and schematic files in your system''s default viewer from the Board Tools page. Use the boardview to jump from a net name to its test points. Cross-reference the schematic to see which IC generates a rail. Log the expected values you find into the board''s test-point index.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('Samsung USB-C Charging Port Replacement', 'Repair Guides/Samsung/Charging', '<p>Most Samsung charging ports are on a replaceable sub-board or flex, which makes no-charge repairs quick when the port is the fault.</p><p>Confirm the fault is the port and not the battery or board before ordering parts.</p><ul><li>Test with a known-good cable and charger.</li><li>Replace the charging port flex/sub-board.</li><li>Verify fast-charge negotiation after the repair.</li></ul>', 'Most Samsung charging ports are on a replaceable sub-board or flex, which makes no-charge repairs quick when the port is the fault. Confirm the fault is the port and not the battery or board before ordering parts. Test with a known-good cable and charger. Replace the charging port flex/sub-board. Verify fast-charge negotiation after the repair.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('TV No Backlight: Strips and Driver', 'Repair Guides/TV/Backlight', '<p>A TV with sound and a faint image under a flashlight but no backlight usually has failed LED strips or a backlight driver fault.</p><p>Measure the backlight voltage and check for an over-current shutdown.</p><ul><li>Confirm the panel shows an image with a flashlight (backlight-only fault).</li><li>Measure the LED driver output; a protection shutdown points to a shorted strip.</li><li>Replace the failed LED strips as a set and re-test.</li></ul>', 'A TV with sound and a faint image under a flashlight but no backlight usually has failed LED strips or a backlight driver fault. Measure the backlight voltage and check for an over-current shutdown. Confirm the panel shows an image with a flashlight (backlight-only fault). Measure the LED driver output; a protection shutdown points to a shorted strip. Replace the failed LED strips as a set and re-test.');
INSERT INTO knowledge_articles (title, category, body_html, body_text) VALUES ('TV No Power: Power Board and Capacitors', 'Repair Guides/TV/Power', '<p>A dead TV often has a failed power (SMPS) board, frequently bulging or vented capacitors on the standby supply.</p><p>Standby voltage should be present whenever the set is plugged in.</p><ul><li>Measure the standby rail on the power board.</li><li>Inspect for bulging/leaking capacitors and replace the affected ones.</li><li>Re-test standby and power-on sequencing.</li></ul>', 'A dead TV often has a failed power (SMPS) board, frequently bulging or vented capacitors on the standby supply. Standby voltage should be present whenever the set is plugged in. Measure the standby rail on the power board. Inspect for bulging/leaking capacitors and replace the affected ones. Re-test standby and power-on sequencing.');
